    @Test
    @DisplayName("parse(html, baseUri) throws IllegalArgumentException when html is null")
    public void test_TC01() {
        String html = null;
        String baseUri = "http://example.com";
        // Check if html is null before passing it to Jsoup.parse
        if (html == null) throw new IllegalArgumentException("html cannot be null");
        // html == null → expect NPE
        assertThrows(NullPointerException.class, () -> Jsoup.parse(html, baseUri));
    }

    @Test
    @DisplayName("parse(html, baseUri) returns empty Document when html is empty string and baseUri is empty")
    public void test_TC02() {
        String html = "";
        String baseUri = "";
        // html non-null and baseUri empty → empty body
        Document doc = Jsoup.parse(html, baseUri);
        assertNotNull(doc);
        assertTrue(doc.body().children().isEmpty(), "Body should have no children");
        assertEquals("", doc.baseUri(), "Base URI should be empty");
    }

    @Test
    @DisplayName("parse(html, baseUri) correctly resolves relative URLs when baseUri non-empty")
    public void test_TC03() {
        String html = "<a href=\"page.html\">link</a>";
        String baseUri = "http://example.com/path/";
        // html non-null and baseUri non-empty → resolve relative link
        Document doc = Jsoup.parse(html, baseUri);
        Element a = doc.selectFirst("a");
        assertNotNull(a);
        assertEquals("http://example.com/path/page.html", a.attr("abs:href"),
                "abs:href should resolve against baseUri");
    }

    @Test
    @DisplayName("parse(html) delegates to parse(html,\"") and returns Document with body fragment")
    public void test_TC04() {
        String html = "<p>test</p>";
        // no-base overload uses empty baseUri
        Document doc = Jsoup.parse(html);
        assertNotNull(doc);
        assertEquals("<p>test</p>", doc.body().html());
    }

