    @DisplayName("parse(html, parser) uses custom parser to parse xml fragment")
    public void test_TC05() {
        String html = "<root><child/></root>";
        Parser parser = Parser.xmlParser();
        // xmlParser should parse <child/> as element
        Document doc = Jsoup.parse(html, parser);
        assertNotNull(doc);
        assertEquals(1, doc.select("child").size());
    }

