        String html = "<img src='img.png'>";
        String baseUri = "http://host/";
        Parser parser = Parser.xmlParser();
        // xmlParser with non-empty baseUri resolves abs:src
        Document doc = Jsoup.parse(html, baseUri, parser);
        Element img = doc.selectFirst("img");
        assertNotNull(img);
        assertEquals("http://host/img.png", img.attr("abs:src"));
    }

